// Функция для очистки от Markdown (обратных кавычек)
function stripCodeFences(s) {
  s = s.trim();
  s = s.replace(/^`{3}(?:json)?\s*/i, '');
  s = s.replace(/`{3}$/i, '');
  return s.trim();
}

// Функция безопасного парсинга JSON
function tryParseJson(raw) {
  try { return JSON.parse(raw); } catch (_) {}

  let fixed = raw.replace(/\uFEFF/g, '');
  fixed = fixed.replace(/,\s*([}\]])/g, '$1');

  try { return JSON.parse(fixed); } 
  catch (e) { return { error: 'invalid_json', message: e.message, raw: raw }; }
}

// Берем данные строго из указанного узла
const inputItems = $('Проверка сообщения в AI').all();

return inputItems.map((item) => {
  const j = item.json || {};

  // 1. Достаем сам текст ответа строго из структуры OpenRouter (или фолбэк для других)
  let rawContent = '';
  if (j.choices && j.choices[0] && j.choices[0].message) {
    rawContent = j.choices[0].message.content || '';
  } else if (typeof j.text === 'string') {
    rawContent = j.text;
  } else if (typeof j.message === 'string') {
    rawContent = j.message;
  }

  // 2. Автоматически забираем токены и деньги для статистики
  const usage = j.usage || {};
  const metaData = {
    _total_tokens: usage.total_tokens || 0,
    _cost_usd: usage.cost || 0
  };

  rawContent = String(rawContent).trim();

  if (!rawContent) {
    return { json: { error: 'empty_ai_output', raw: '', ...metaData } };
  }

  // Нормализуем переносы
  const normalized = rawContent.replace(/\r\n/g, '\n').trim();

  // 3. ПРАВИЛЬНАЯ ПРОВЕРКА НА PASS
  // Если ответ начинается с "PASS" (например, "PASS 0%" или "PASS 57%")
  if (normalized.startsWith('PASS')) {
    return { 
      json: { 
        тип_лида: 'PASS',
        совпадение: normalized.replace('PASS', '').trim(), 
        ...metaData
      } 
    };
  }

  // 4. Если это не PASS, значит ИИ должен был вернуть JSON
  let candidate = stripCodeFences(normalized);
  const first = candidate.search(/[{[]/);
  if (first > 0) candidate = candidate.slice(first).trim();

  const parsed = tryParseJson(candidate);

  // Если ИИ выдал кривой JSON, передаем ошибку дальше, не ломая воркфлоу
  if (parsed.error) {
    return { json: { ...parsed, ...metaData } };
  }

  // 5. Успех! Возвращаем чистый распарсенный JSON + данные по токенам и стоимости
  return { json: { ...parsed, ...metaData } };
});

