// n8n Code node (JavaScript)
// Ожидает во входном item поля:
// - text: текст сообщения
// - username: username в Telegram (можно с @ или без)

const items = $input.all();

return items.map((item) => {
  const text = (item.json.text ?? '').toString();
  let username = (item.json.username ?? '').toString().trim();

  // Убираем @ в начале, если есть
  username = username.replace(/^@/, '');

  // Кодируем текст для URL
  const encodedText = encodeURIComponent(text);

  // Собираем ссылку
  const tgLink = `https://t.me/${username}?text=${encodedText}`;

  return {
    json: {
      ...item.json,
      tg_link: tgLink,
    },
  };
});

